@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea class="form-control mb-3" rows="12" @bind="content" @bind:event="oninput"></textarea>

<div class="d-flex align-items-center gap-3 mb-2">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt</span>
    }
</div>

@code {
    private const string StorageKey = "notepad-content";

    private string content = string.Empty;
    private string savedContent = string.Empty;
    private string? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    private bool HasUnsavedChanges => content != savedContent;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (!firstRender) return;

        module = await JS.InvokeAsync<IJSObjectReference>(
            "import", Assets["Components/Pages/Notepad.razor.js"]);

        var stored = await module.InvokeAsync<string?>("load", StorageKey);
        if (!string.IsNullOrEmpty(stored))
        {
            content = stored;
            savedContent = stored;
            StateHasChanged();
        }

        autoSaveTimer = new System.Threading.Timer(
            async _ => await InvokeAsync(AutoSave), null,
            TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));
    }

    private async Task AutoSave()
    {
        if (!HasUnsavedChanges || module is null) return;
        await Save();
        StateHasChanged();
    }

    private async Task SaveNow()
    {
        if (module is null) return;
        await Save();
    }

    private async Task Save()
    {
        await module!.InvokeVoidAsync("save", StorageKey, content);
        savedContent = content;
        lastSavedAt = DateTime.Now.ToString("HH:mm:ss");
        await module!.InvokeVoidAsync("setUnsaved", false);
    }

    private async Task Clear()
    {
        if (module is null) return;
        content = string.Empty;
        savedContent = string.Empty;
        lastSavedAt = null;
        await module.InvokeVoidAsync("remove", StorageKey);
        await module.InvokeVoidAsync("setUnsaved", false);
    }

    protected override async Task OnAfterRenderAsync_UpdateBeforeUnload()
    {
        // This is handled via the oninput binding + a periodic check approach
    }

    // Keep the beforeunload guard in sync after every render
    protected override void OnAfterRender(bool firstRender)
    {
        if (module is not null)
        {
            _ = module.InvokeVoidAsync("setUnsaved", HasUnsavedChanges);
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
        {
            await autoSaveTimer.DisposeAsync();
        }
        if (module is not null)
        {
            await module.InvokeVoidAsync("setUnsaved", false);
            await module.DisposeAsync();
        }
    }
}

